import React from 'react';
import { Grid, Paper, Button, Typography, TextField } from '@mui/material';
import { makeStyles } from '@mui/styles'; // Only import makeStyles from @mui/styles
import { useNavigate } from 'react-router-dom';
import signpng from './signupfinal.png';
import signback from './signback.png'

// Import ThemeProvider and createTheme from @mui/material/styles
import { ThemeProvider, createTheme } from '@mui/material/styles';

// Define your theme
const theme = createTheme();

const useStyles = makeStyles((theme) => ({
    imageContainer: {
    position: 'relative',
    },
    image: {
    position: 'absolute',
    top: 0,
    left: 0,
    width: 'auto',
    height: '600px',
    zIndex: 2,
    },
  image2: {
    position: 'absolute',
    top: 0,
    left: 0,
    width: 'auto',
    height: '600px',
    margin: '0 0 0 10px',
    zIndex: 1,
  },
}));

export const Signup = () => {
  const navigate = useNavigate();
  const classes = useStyles();

  return (
    <ThemeProvider theme={theme}>
      <Grid
        container
        justifyContent="center"
        alignItems="center"
        style={{ minHeight: '100vh' }}
      >
        <Paper sx={{ padding: '20px,200px,0px,0px', width: '1200px', height: '600px' }} elevation={10}>

          <Grid container>
            <Grid item xs={6} className={classes.imageContainer}>
              <img src={signpng} alt="The signup" className={classes.image} />
              <img src={signback} alt="The signup" className={classes.image2} />
            </Grid>
            <Grid item xs={6} container justifyContent="center" alignItems="center" style={{ zIndex: 1 }}>
              <Typography variant="h2">Hello world how are you</Typography>
              <TextField label="Name" variant="outlined" fullWidth margin="normal" />
              <TextField label="Password" type="password" variant="outlined" fullWidth margin="normal" />
              <Button variant="contained" onClick={() => { navigate('/signup') }}>Signup</Button>
            </Grid>
          </Grid>
        </Paper>
      </Grid>
    </ThemeProvider>
  );
};

export default Signup;
